use strict;
use warnings;
use PDF::API2;
use Text::CSV;

my $pdf = PDF::API2->open($ARGV[0]);
my $text = "";

# Loop through each page to extract text
for (my $page = 1; $page <= $pdf->pages; $page++) {
    my $page_obj = $pdf->page($page);
    $text .= $page_obj->text;
}

# Save the extracted text to a CSV file
my $csv = Text::CSV->new({ binary => 1, auto_diag => 2 });
open my $fh, '>', 'output.csv' or die "Can't open output.csv for writing: $!";

# Write a header row
